const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const quotes = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// Find qualifying rear extension packages between 20–30 sqm and <= $80,000
const qualifyingPackages = packages.filter(p => 
  p.category_id === 'extensions' &&
  p.project_type === 'rear_extension' &&
  typeof p.size_sqm === 'number' && p.size_sqm >= 20 && p.size_sqm <= 30 &&
  typeof p.price === 'number' && p.price <= 80000
);

let cheapestPackage = null;
for (const p of qualifyingPackages) {
  if (!cheapestPackage || p.price < cheapestPackage.price) {
    cheapestPackage = p;
  }
}

let quotesForCheapest = [];
if (cheapestPackage) {
  quotesForCheapest = quotes.filter(q => q.package_id === cheapestPackage.id);
}

// CP1 (0.40): User submitted a quote request for the cheapest qualifying package
checkpoints.push({
  passed: !!cheapestPackage && quotesForCheapest.length > 0,
  weight: 0.40
});

// Among those, check postcode and budget
const quotesWithDetails = quotesForCheapest.filter(q => 
  q.postcode === '3000' && Number(q.budget) === 80000
);

// CP2 (0.30): Quote request for the cheapest package includes correct postcode and budget
checkpoints.push({
  passed: quotesWithDetails.length > 0,
  weight: 0.30
});

// Check note content
const quotesWithNote = quotesWithDetails.filter(q => 
  (q.note || '').trim() === '25 sqm rear extension with open-plan kitchen'
);

// CP3 (0.30): Quote request also includes the correct note about a 25 sqm rear extension with open-plan kitchen
checkpoints.push({
  passed: quotesWithNote.length > 0,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const bookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]');

// Find qualifying kitchen renovation packages under $35,000
const qualifyingPackages = packages.filter(p => 
  p.category_id === 'kitchen_renovations' &&
  p.project_type === 'kitchen_renovation' &&
  typeof p.price === 'number' && p.price <= 35000
);

let cheapestPackage = null;
for (const p of qualifyingPackages) {
  if (!cheapestPackage || p.price < cheapestPackage.price) {
    cheapestPackage = p;
  }
}

let bookingsForCheapest = [];
if (cheapestPackage) {
  bookingsForCheapest = bookings.filter(b => 
    b.package_id === cheapestPackage.id &&
    b.project_type === 'kitchen_renovation'
  );
}

// CP1 (0.40): Consultation booking exists for the cheapest qualifying kitchen package
checkpoints.push({
  passed: !!cheapestPackage && bookingsForCheapest.length > 0,
  weight: 0.40
});

// Filter to afternoon slots between 2–4 pm (2:00 pm or 3:00 pm)
const afternoonBookings = bookingsForCheapest.filter(b => 
  b.time_of_day === 'afternoon' &&
  (b.time_slot_label === '2:00 pm' || b.time_slot_label === '3:00 pm')
);

// CP2 (0.30): Booking is for an afternoon slot between 2 pm and 4 pm
checkpoints.push({
  passed: afternoonBookings.length > 0,
  weight: 0.30
});

// From those, check that the date is a Wednesday
const wedAfternoonBookings = afternoonBookings.filter(b => {
  const d = new Date(b.consultation_date);
  return !isNaN(d.getTime()) && d.getDay() === 3; // 3 = Wednesday
});

// CP3 (0.30): Booking falls on a Wednesday afternoon
checkpoints.push({
  passed: wedAfternoonBookings.length > 0,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const compareSets = JSON.parse(localStorage.getItem('package_compare_sets') || '[]');
const compareItems = JSON.parse(localStorage.getItem('package_compare_items') || '[]');
const shortlistItems = JSON.parse(localStorage.getItem('package_shortlist_items') || '[]');

const activeSet = compareSets.find(cs => cs && cs.is_active);
let comparedPackages = [];
if (activeSet) {
  const comparedIds = compareItems
    .filter(it => it.compare_set_id === activeSet.id)
    .map(it => it.package_id);
  comparedPackages = packages.filter(p => comparedIds.includes(p.id));
}

// Qualifying compared extensions under $120,000
const qualifyingCompared = comparedPackages.filter(p => 
  p.category_id === 'extensions' &&
  typeof p.price === 'number' && p.price <= 120000
);

let largestPackage = null;
for (const p of qualifyingCompared) {
  const area = typeof p.added_floor_area_sqm === 'number' ? p.added_floor_area_sqm : 0;
  if (!largestPackage || area > (typeof largestPackage.added_floor_area_sqm === 'number' ? largestPackage.added_floor_area_sqm : 0)) {
    largestPackage = p;
  }
}

const shortlistedIds = shortlistItems.map(it => it.package_id);

// CP1 (0.40): User compared at least two qualifying extension packages under $120,000
checkpoints.push({
  passed: qualifyingCompared.length >= 2,
  weight: 0.40
});

// CP2 (0.60): Among compared packages, the one with the largest added floor area is in the shortlist
checkpoints.push({
  passed: !!largestPackage && shortlistedIds.includes(largestPackage.id),
  weight: 0.60
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const ideasItems = JSON.parse(localStorage.getItem('ideas_list_items') || '[]');

const savedProjectIds = ideasItems.map(it => it.project_id);

const qualifyingSaved = savedProjectIds.filter(id => {
  const p = projects.find(pr => pr.id === id);
  return p &&
    p.project_type === 'loft_conversion' &&
    typeof p.completion_year === 'number' && p.completion_year >= 2023 &&
    typeof p.rating === 'number' && p.rating >= 4.5;
});

const count = qualifyingSaved.length;

// CP1 (0.20): At least 1 qualifying loft conversion project saved
checkpoints.push({ passed: count >= 1, weight: 0.20 });
// CP2 (0.30): At least 2 qualifying projects saved
checkpoints.push({ passed: count >= 2, weight: 0.30 });
// CP3 (0.50): At least 3 qualifying projects saved
checkpoints.push({ passed: count >= 3, weight: 0.50 });

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const estimates = JSON.parse(localStorage.getItem('cost_estimates') || '[]');
const emails = JSON.parse(localStorage.getItem('cost_estimate_emails') || '[]');

// Find estimates matching the required parameters
const targetEstimates = estimates.filter(e => 
  e.project_type === 'full_home_renovation' &&
  e.bedrooms === 3 &&
  e.bathrooms === 2 &&
  e.finish_level === 'mid_range' &&
  Number(e.budget) === 180000
);

// CP1 (0.40): User generated at least one matching cost estimate
checkpoints.push({
  passed: targetEstimates.length > 0,
  weight: 0.40
});

// Check for an email sent for one of these estimates to user@example.com
let emailMatch = false;
for (const em of emails) {
  if (targetEstimates.some(te => te.id === em.estimate_id) && em.recipient_email === 'user@example.com') {
    emailMatch = true;
    break;
  }
}

// CP2 (0.60): User emailed the summary for a matching estimate to user@example.com
checkpoints.push({
  passed: emailMatch,
  weight: 0.60
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchParams = JSON.parse(localStorage.getItem('task6_searchParams') || 'null');
const savedMeta = JSON.parse(localStorage.getItem('task6_savedArticleMeta') || 'null');
const reopenedId = localStorage.getItem('task6_reopenedArticleId') || null;
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Helper to check if an article is about planning permits for extensions and 2023+
function isPlanningPermitExtensionArticle(article) {
  if (!article) return false;
  const yearOk = typeof article.year === 'number' && article.year >= 2023;
  const title = (article.title || '').toLowerCase();
  const content = (article.content || '').toLowerCase();
  const tags = Array.isArray(article.tags) ? article.tags.map(t => t.toLowerCase()) : [];

  const tagMatch = tags.some(t => t.includes('planning permit') && t.includes('extension'));
  const textMatch = (title.includes('planning permit') || content.includes('planning permit')) &&
                    (title.includes('extension') || content.includes('extension'));
  return yearOk && (tagMatch || textMatch);
}

// CP1 (0.30): User searched with a query mentioning planning permits and extensions, with min_year >= 2023
let cp1Passed = false;
if (searchParams) {
  const q = (searchParams.query || '').toLowerCase();
  const minYear = typeof searchParams.min_year === 'number' ? searchParams.min_year : null;
  const mentionsPlanning = q.includes('planning permit');
  const mentionsExtension = q.includes('extension');
  cp1Passed = mentionsPlanning && mentionsExtension && minYear !== null && minYear >= 2023;
}
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// CP2 (0.40): User saved a qualifying planning-permit-for-extensions article to the reading list
let cp2Passed = false;
let savedArticle = null;
if (savedMeta && savedMeta.article_id) {
  savedArticle = articles.find(a => a.id === savedMeta.article_id);
  const inReadingList = readingItems.some(ri => ri.article_id === savedMeta.article_id);
  cp2Passed = isPlanningPermitExtensionArticle(savedArticle) && inReadingList;
}
checkpoints.push({ passed: cp2Passed, weight: 0.40 });

// CP3 (0.30): User reopened the same qualifying article from the reading list
let cp3Passed = false;
if (cp2Passed && reopenedId && savedMeta && savedMeta.article_id) {
  cp3Passed = reopenedId === savedMeta.article_id;
}
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const faqs = JSON.parse(localStorage.getItem('faq_items') || '[]');
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

const bathroomWarrantyFaq = faqs.find(f => Array.isArray(f.keywords) && f.keywords.includes('bathroom renovation warranty'));

let candidateMessages = [];
if (bathroomWarrantyFaq) {
  candidateMessages = messages.filter(m => 
    m.related_faq_id === bathroomWarrantyFaq.id &&
    m.source_page === 'faq_page'
  );
}

// CP1 (0.40): At least one contact message was sent from the FAQ page linked to the bathroom renovation warranty FAQ
checkpoints.push({
  passed: candidateMessages.length > 0,
  weight: 0.40
});

// Filter to messages with correct subject and that mention warranty
const followupMessages = candidateMessages.filter(m => 
  m.subject_type === 'bathroom_renovation' &&
  typeof m.message === 'string' && m.message.toLowerCase().includes('warranty')
);

// CP2 (0.30): Message is a follow-up about bathroom renovation warranty (subject and content)
checkpoints.push({
  passed: followupMessages.length > 0,
  weight: 0.30
});

// From those, check that contact details (email and phone) are provided and look valid
const detailedMessages = followupMessages.filter(m => {
  const email = m.email || '';
  const phone = m.phone || '';
  const emailOk = email.includes('@');
  const phoneDigits = phone.replace(/\D/g, '');
  const phoneOk = phoneDigits.length >= 8;
  return emailOk && phoneOk;
});

// CP3 (0.30): Follow-up message includes usable email and phone contact details
checkpoints.push({
  passed: detailedMessages.length > 0,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('renovation_plans') || '[]');
const planProjects = JSON.parse(localStorage.getItem('renovation_plan_projects') || '[]');

// Find submitted plans that contain both required projects
const candidatePlans = plans.filter(p => p.status === 'submitted').filter(p => {
  const projects = planProjects.filter(pp => pp.plan_id === p.id);
  const hasBathroom = projects.some(prj => 
    prj.project_type === 'bathroom_renovation' &&
    Number(prj.budget) === 20000 &&
    prj.property_type === 'apartment'
  );
  const hasDeck = projects.some(prj => 
    prj.project_type === 'deck_extension' &&
    Number(prj.budget) === 25000 &&
    prj.property_type === 'house'
  );
  return hasBathroom && hasDeck;
});

// CP1 (0.60): At least one submitted plan includes both the $20k apartment bathroom and $25k house deck projects
checkpoints.push({
  passed: candidatePlans.length > 0,
  weight: 0.60
});

// Among those plans, check that contact details are populated
const completedPlans = candidatePlans.filter(p => {
  const nameOk = !!(p.name && p.name.trim());
  const emailOk = !!(p.email && p.email.includes('@'));
  const phoneOk = !!(p.phone && p.phone.trim());
  const postcodeOk = !!(p.postcode && p.postcode.trim());
  return nameOk && emailOk && phoneOk && postcodeOk;
});

// CP2 (0.40): Plan with required projects also includes filled-in contact details
checkpoints.push({
  passed: completedPlans.length > 0,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
